// Ordena as mensagens pela data
items.sort((a, b) =>
  new Date(a.json.created_at).getTime() - new Date(b.json.created_at).getTime()
);

function formatarData(isoDate) {
  const d = new Date(isoDate);
  const dia = String(d.getDate()).padStart(2, "0");
  const mes = String(d.getMonth() + 1).padStart(2, "0");
  const ano = d.getFullYear();
  return `${dia}/${mes}/${ano}`;
}

const historico = [];

for (const item of items) {
  const row = item.json;
  const data = formatarData(row.created_at);

  if (row.mensagem_usuario?.trim()) {
    historico.push({
      autor: "Usuário",
      mensagem: row.mensagem_usuario.trim(),
      data
    });
  }

  if (row.mensagem_agente?.trim()) {
    historico.push({
      autor: "Agente",
      mensagem: row.mensagem_agente.trim(),
      data
    });
  }
}

// =====================================================
// NOVO TRECHO → Conta mensagens seguidas do agente
// =====================================================
let qtd_mensagens_sem_resposta = 0;

for (let i = historico.length - 1; i >= 0; i--) {
  if (historico[i].autor === "Agente") {
    qtd_mensagens_sem_resposta++;
  } else {
    break; // usuário falou → reset
  }
}
// =====================================================

return [
  {
    json: {
      historico_conversa: historico,
      qtd_mensagens_sem_resposta
    }
  }
];

function tryFixJson(text) {
  if (!text) return null;

  return text
    .replace(/^[^{[]+/, '')               // remove qualquer lixo antes do JSON
    .replace(/```json|```/g, '')         // remove markdown se vier
    .replace(/[\u0000-\u001F]+/g, '')    // remove caracteres invisíveis
    .replace(/(\w+)\s*:/g, '"$1":')      // força aspas nas chaves
    .replace(/'/g, '"')                  // troca aspas simples por duplas
    .replace(/\n/g, ' ')
    .replace(/,\s*}/g, '}')
    .replace(/,\s*]/g, ']')
    .trim();
}

function safeParse(raw) {
  if (!raw) return {};

  try {
    return JSON.parse(raw);
  } catch (e) {
    try {
      return JSON.parse(tryFixJson(raw));
    } catch (err) {
      return {};
    }
  }
}

function normalizeEnum(value, allowed, fallback = '') {
  if (!value) return fallback;
  return allowed.includes(value) ? value : fallback;
}

return items.map(item => {

  const raw = item.json.output?.trim();
  const data = safeParse(raw);

  const leadNotion = $('Pega os leads do Notion').item.json;

   // ENUMS ATUALIZADOS
  const temperaturas = [
    "FRIO",
    "MORNO",
    "QUENTE",
    "MUITO QUENTE",
    "SEM HISTORICO"
  ];

  const barreiras = [
    "PREÇO",
    "TEMPO",
    "CREDIBILIDADE",
    "INSEGURANÇA PESSOAL",
    "FALTA DE PRIORIDADE",
    "SEM BARREIRA CLARA",
    "SEM INTERESSE"
  ];

  return {
    json: {
      nota: typeof data.nota === 'number' ? data.nota : null,

      temperatura: normalizeEnum(
        data.temperatura,
        temperaturas,
        "SEM HISTORICO"
      ),

      principal_barreira: normalizeEnum(
        data.principal_barreira,
        barreiras,
        "SEM INTERESSE"
      ),

      mensagem_resumo: data.mensagem_resumo ?? '',

      id: leadNotion.id,
      url: leadNotion.url
    },
  };
});

