function normalizeStatus(value) {
  const allowed = ["Desqualificado", "Geladeira"];
  if (!value) return "Desqualificado";

  // Corrige pequenas variações da IA
  const clean = value.trim();

  if (allowed.includes(clean)) return clean;

  if (clean.toLowerCase().includes("gel")) return "Geladeira";
  if (clean.toLowerCase().includes("des")) return "Desqualificado";

  return "Desqualificado";
}

